// Map service slugs to hero images
export function getServiceHeroImage(slug: string): string {
  const map: Record<string, string> = {
    "system-design-consultancy": HERO_IMAGES.about,
    "consultation-design": HERO_IMAGES.about,
    "system-integration": HERO_IMAGES["smart-intelligent-solutions"],
    "installation-commissioning": HERO_IMAGES.services,
    "testing-integration": HERO_IMAGES["light-current-elv"],
    "maintenance-support": HERO_IMAGES["light-current-elv"],
    "maintenance-after-sales": HERO_IMAGES["light-current-elv"],
    "training-certification": HERO_IMAGES.training,
    "technical-training-support": HERO_IMAGES.training,
    "project-management": HERO_IMAGES.projects,
    "annual-maintenance-contracts": HERO_IMAGES.partners,
    "upgrades-retrofits": HERO_IMAGES["fire-life-safety"],
  };
  return map[slug] || HERO_IMAGES.services;
}

